import{_ as r,o as t,c as p,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"鸢尾花之誓","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/3.C级/鸢尾花之誓.md","filePath":"4.资源分区/7.物品与装备/3.防具/3.C级/鸢尾花之誓.md"}'),o={name:"4.资源分区/7.物品与装备/3.防具/3.C级/鸢尾花之誓.md"};function d(l,e,_,i,c,h){return t(),p("div",null,[...e[0]||(e[0]=[a("h1",{id:"鸢尾花之誓",tabindex:"-1"},[n("鸢尾花之誓 "),a("a",{class:"header-anchor",href:"#鸢尾花之誓","aria-label":'Permalink to "鸢尾花之誓"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),s('<h1 id="鸢尾花之誓-1" tabindex="-1">鸢尾花之誓 <a class="header-anchor" href="#鸢尾花之誓-1" aria-label="Permalink to &quot;鸢尾花之誓&quot;">​</a></h1><p>鸢尾花之誓<br> 魔幻本质<br> C+3000<br> 描述：阿斯特利亚，一个魔法与科技交织，冷热兵器并存的王国，因其身着女仆装的骑士们组成的鸢尾花卫队闻名。卫队少女们不仅要面对来自魔法生物的威胁，还需要对抗日益强大的火器与机械兵器。因此其装备充分融合了魔法与科技，而其中“鸢尾花之誓”，正是少女们手中最具代表性的装备。</p><p>这是一面高大优雅且整体形状为流线型的塔盾，由相对轻量化的魔法合金和高科技材料制成。盾牌的表面覆盖着精美的粉色的鸢尾花纹，边缘装饰有镶刻的银色饰边。盾牌的中央预留了一个侧面射击口，配合盾牌后的枪械支架，使用者能够在保持防护的同时，方便地使用小型自动火力进行精准射击。</p><p>盾牌的核心技术之一为外骨骼驱动系统。这套辅助装置可以适配不同的穿着需求，通过巧妙的设计将使用者与盾牌本体紧密结合，并能够根据使用者的姿势自动调整重心与支撑力，使得使用者即使身穿女仆装或其他服饰，也能够不妨碍射击动作。</p><p>当战斗进入近身时，塔盾能够通过术式与外骨骼系统的配合，自动分离成双侧护盾在两侧进行防护。以牺牲射击稳定性和部分远距离为代价，为使用者提供了更高的机动性以及相应的近距离防护。</p><p>这是一面伤害3l，格挡11，具有【防弹】特性的重盾，风度需求为6。其配备有内源外骨骼协助驱动，单手与外骨骼共同使用时力量需求为4。当使用者力量达到6时，其提供的内源力量即可支持将塔盾全部交由外骨骼操控。<br> PS：目前提供的盾牌形态及功能为制式基础版本。</p><p>反射计算：塔盾内搭载了精巧的辅助程式，使用者即便并不会使用盾牌，辅助程式也能将使用者发出的指令与盾牌的反馈互相编译传递，以另一种形式来实现精准高效的格挡操控。无需动作，只需消耗1点意志或3点能量激活鸢尾花之誓中的预载术式，本场景中即可以使用【射击+对应枪械专业】来进行格挡。同样得益于外骨骼系统的辅助传动，格挡动作将变得极为流畅。每轮一次，使用者获得2点可用于格挡动作的ap。</p><p>形态切换：通过简单的手部动作指令，鸢尾花之誓可以在远程和近战两种形态中进行切换，切换过程以自由动作跟随在使用者的格挡动作中。架起防御的一瞬间，鸢尾花之誓的形态切换便会在这过程中完成，每回合只能进行一次形态切换，进行形态切换需要你已经开启了反射计算的效果。</p><p>远程形态：当盾牌处于远程作战模式时，呈现出典型的塔盾形态。此时，盾牌提供2点针对远程攻击的全伤害吸收。塔盾的相关术式也会激活，盾面后方会变得单向透明，能如屏幕般投影出相应的弹道计算结果并进行主动红外探测，配合稳固的枪械支架作用，能有效提升枪械开火时的准确性。使用者的射击检定增加1点器械加值，并对前方获得黑暗视觉。</p><p>近战形态：当战斗进入近身时，盾牌通过外骨骼和预设术式自动从中心分离成双侧护盾的形式，格挡时则转为交叠的格挡形态。此时，盾牌提供的伤害吸收会变为远近各1点，并且失去射击检定加成和黑暗视觉。近战形态下，鸢尾花之誓中相应的推进装置激活，使用者可以借助其产生的爆发动力，以跳跃代替移动。此状态下你可以在正常移动距离后追加一次跳跃检定，额外移动成功数/米，视为已助跑。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
